#include <bits/stdc++.h>
using namespace std;

const int N = 1e5 + 10;
int MOD;
long long a[N], d[4 * N], tag_add[4 * N], tag_mul[4 * N];

inline void push_up(int x) {
    d[x] = (d[x * 2] + d[x * 2 + 1]) % MOD;
}

void push_down(int x, int ln, int rn) {
    int l = x * 2, r = x * 2 + 1;
    if (tag_mul[x] != 1) {
        tag_mul[l] = (long long)tag_mul[l] * tag_mul[x] % MOD;
        tag_mul[r] = (long long)tag_mul[r] * tag_mul[x] % MOD;
        tag_add[l] = (long long)tag_add[l] * tag_mul[x] % MOD;
        tag_add[r] = (long long)tag_add[r] * tag_mul[x] % MOD;
        d[l] = (long long)d[l] * tag_mul[x] % MOD;
        d[r] = (long long)d[r] * tag_mul[x] % MOD;
        tag_mul[x] = 1;
    }
    if (tag_add[x]) {
        d[l] = (d[l] + (long long)tag_add[x] * ln) % MOD;
        d[r] = (d[r] + (long long)tag_add[x] * rn) % MOD;
        tag_add[l] = (tag_add[l] + tag_add[x]) % MOD;
        tag_add[r] = (tag_add[r] + tag_add[x]) % MOD;
        tag_add[x] = 0;
    }
}

void build(int x, int l, int r) {
    tag_mul[x] = 1;
    tag_add[x] = 0;
    if (l == r) {
        d[x] = a[l] % MOD;
        return;
    }
    int mid = (l + r) >> 1;
    build(x * 2, l, mid);
    build(x * 2 + 1, mid + 1, r);
    push_up(x);
}

void update_add(int x, int l, int r, int a, int b, int v) {
    if (l >= a && r <= b) {
        d[x] = (d[x] + (long long)v * (r - l + 1)) % MOD;
        tag_add[x] = (tag_add[x] + v) % MOD;
        return;
    }
    int mid = (l + r) >> 1;
    push_down(x, mid - l + 1, r - mid);
    if (a <= mid) 
        update_add(x * 2, l, mid, a, b, v);
    if (b > mid) 
        update_add(x * 2 + 1, mid + 1, r, a, b, v);
    push_up(x);
}

void update_mul(int x, int l, int r, int a, int b, int v) {
    if (l >= a && r <= b) {
        d[x] = (long long)d[x] * v % MOD;
        tag_mul[x] = (long long)tag_mul[x] * v % MOD;
        tag_add[x] = (long long)tag_add[x] * v % MOD;
        return;
    }
    int mid = (l + r) >> 1;
    push_down(x, mid - l + 1, r - mid);
    if (a <= mid) 
        update_mul(x * 2, l, mid, a, b, v);
    if (b > mid) 
        update_mul(x * 2 + 1, mid + 1, r, a, b, v);
    push_up(x);
}

long long query(int x, int l, int r, int a, int b) {
    if (a <= l && r <= b) 
        return d[x];
    int mid = (l + r) >> 1;
    push_down(x, mid - l + 1, r - mid);
    long long sum = 0;
    if (a <= mid)
        sum = (sum + query(x * 2, l, mid, a, b)) % MOD;
    if (b > mid) 
        sum = (sum + query(x * 2 + 1, mid + 1, r, a, b)) % MOD;
    return sum % MOD;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    int n, q;
    cin >> n >> q >> MOD;
    for (int i = 1; i <= n; i++) 
        cin >> a[i];
    build(1, 1, n);
    while (q--) {
        int op, x, y;
        cin >> op >> x >> y;
        if (op == 1) {
            int k;
            cin >> k;
            update_mul(1, 1, n, x, y, k);
        } else if (op == 2) {
            int k;
            cin >> k;
            update_add(1, 1, n, x, y, k);
        } else {
            cout << query(1, 1, n, x, y) % MOD << '\n';
        }
    }
    return 0;
}
